  ('heelevel3-d0d1b9a2-moex-00391', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '會計師對依其他綜合會計基礎編製之財務報表所簽發之特殊目的查核報告，下列敘述何者正確？', '["在意見段之後增加解釋段，說明財務報表編製與附註之會計基礎", "財務報表名稱在報告前言段中應清楚揭示所依據之基礎", "查核報告不可以限制使用對象", "報告不得標明「會計師查核報告」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00392', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '關於影響查核人員確定內部稽核職能專業能力之因素，下列敘述何者錯誤？', '["內部稽核人員是否經專業訓練且具備足夠之稽核能力", "內部稽核職能是否依受查者之規模及營運性質獲得足夠及適當之資源", "治理單位是否監督與內部稽核職能有關之聘僱決策", "內部稽核人員是否具備與受查者之財務報導及適用之財務報導架構有關的知識"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00393', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-0e802df0', 'sub-heelevel3-d0d1b9a2-05', NULL, 'single_choice', '下列何者非屬電腦資訊系統之一般控制？', '["建立電腦資訊系統作業之組織架構", "應用系統開發與維護控制", "處理及電腦交易資料檔控制", "新系統軟體之授權、核准、測試及導入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "ebce2a12ce0a", "answer_pdf_sha1": "45ac4217f984", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00394', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'essay', '新北公司生產太陽能面板，在將矽原料加工到完成的太陽能面板中，一
個重要的步驟是在組裝部門。在這個部門裡，材料是在製程開始時投入，
加工成本則是平均發生。
在2021年11月，新北公司的組裝部門有期初在製品2,400單位的面板，
其材料投入 100%，加工成本已投入 40%；當期開始投入單位數 13,000 單
位，期末在製品為3,600單位，其材料投入100%；加工成本已投入70%。
組裝部門的檢驗點為 60%完工階段，11 月份發生了 1,800 件損壞品，正
常損壞率為完好單位的 12%，該部門 11月份的成本資料如下：
期初在製單位 當期投入成本
直接材料成本 $76,800 $262,000
加工成本 123,000 1,305,000
試作：採加權平均法計算11 月組裝部門的轉出成本、非常損壞成本及期
末在製品成本。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
